 * value was changed.
 */
class IntAtomicImpl {
public:
    explicit IntAtomicImpl(int32_t initial) 
        : m_value(initial), m_lastReportedChange(false) {}

    template <typename F>
    void atomicOperation(F&& op) {
        int32_t oldValue = m_value;
        m_value = op(m_value);
        m_lastReportedChange = (m_value != oldValue);
    }

    template <typename F>
    void atomicOperation(F&& op, bool forceNotify) {
        int32_t oldValue = m_value;
        m_value = op(m_value);
        m_lastReportedChange = (m_value != oldValue) || forceNotify;
    }

    int32_t value() const {
        return m_value;
    }

    bool lastReportedChange() const {
        return m_lastReportedChange;
    }

private:
    int32_t m_value;
    bool m_lastReportedChange;
};

/**
 * Function: test_atomic_compound_helpers
 *
