    // 2. Create IntAtomicImpl instance
    IntAtomicImpl atomic(initial);

    AtomicHelperSnapshot snapshot;

    // 3. Apply atomic compound assignment (add)
    reaction::atomicAddAssign(atomic, 5);
    // 4. Check if add operation reported change
    snapshot.addReportedChange = atomic.lastReportedChange();

    // 5. Apply atomic multiply assignment
    reaction::atomicMultiplyAssign(atomic, 2);
    // 6. Check if multiply operation reported change
    snapshot.multiplyReportedChange = atomic.lastReportedChange();

    // 7. Apply atomic bitwise AND assignment
    reaction::atomicBitwiseAndAssign(atomic, 0xFF);
    // 8. Check if bitwise AND operation reported change
    snapshot.andReportedChange = atomic.lastReportedChange();

    // 9. Apply atomic left shift assignment
    reaction::atomicLeftShiftAssign(atomic, 1);
    // 10. Check if left shift operation reported change
    snapshot.leftShiftReportedChange = atomic.lastReportedChange();

